def token_case(s):
    exception = {'URL', 'ID'}
    tokens = s.split('_')
    camel_case = ''
    for token in tokens:
        if token in exception:
            camel_case += token + '_'
        else:
            if camel_case:
                camel_case += token[0].upper() + token[1:]
            else:
                camel_case += token.lower()
    return camel_case[:-1] if camel_case else camel_case
